graphql.query:
mutation Register($input: RegisterInput!) {
  register(input: $input) {
    token
    user {
      id
      email
      createdAt
    }
  }
}

mutation Login($input: LoginInput!) {
  login(input: $input) {
    token
    user {
      id
      email
      createdAt
    }
  }
}

query Me {
  me {
    id
    email
    createdAt
  }
}

mutation Ingest($input: IngestInput!) {
  ingest(input: $input) {
    documentId
    title
    chunkCount
    status
    message
  }
}

